106	
107		procedure ApplyCmd(			Stream 			: in	integer;
108									Address			: in	integer;
109									MaxSize			: in	integer;
110							signal DaqSm_Cmd 		: out 	DaqSm2DaqDma_Cmd_t;
111							signal DaqSm_Cmd_Vld 	: out 	std_logic;
112							signal Clk				: in 	std_logic) is
113		begin
114			wait until rising_edge(Clk);
115			DaqSm_Cmd_Vld	<= '1';
116			DaqSm_Cmd.Address	<= std_logic_vector(to_unsigned(Address, 32));
117			DaqSm_Cmd.MaxSize	<= std_logic_vector(to_unsigned(MaxSize, 16));
118			DaqSm_Cmd.Stream	<= Stream;
119			wait until rising_edge(Clk);
120			DaqSm_Cmd_Vld	<= '0';
121		end procedure;
122		
123		procedure CheckResp(		Stream 			: in	integer;
124									Size			: in	integer;
125									EndType			: in	EndType_s;
126							signal DaqSm_Resp 		: in 	DaqDma2DaqSm_Resp_t;
127							signal DaqSm_Resp_Vld 	: in 	std_logic;
128							signal DaqSm_Resp_Rdy 	: out 	std_logic;
129							signal 	Clk				: in 	std_logic) is
130		begin
131			DaqSm_Resp_Rdy <= '1';
132			wait until rising_edge(Clk) and DaqSm_Resp_Vld = '1';
133			if Trigger_s = EndType then
134				StdlCompare(1, DaqSm_Resp.Trigger, "CHEK_RESP: Response has not set TRIGGER");
135			else
136				StdlCompare(0, DaqSm_Resp.Trigger, "CHEK_RESP: Response has not cleared TRIGGER");
137			end if;
138			StdlvCompareInt(Size, DaqSm_Resp.Size, "CHEK_RESP: Wrong size in response");
139			IntCompare(Stream, DaqSm_Resp.Stream, "CHEK_RESP: Wrong stream number in response");
140			wait until rising_edge(Clk);
141			StdlCompare(0, DaqSm_Resp_Vld, "CHEK_RESP: Response valid did not go low");		
142		end procedure;
143		
144		procedure ApplyData(		Stream 		: in	integer;
145									Bytes		: in	integer;	
146									EndType		: in	EndType_s;
147							signal 	Inp_Vld 	: out 	std_logic_vector;
148							signal 	Inp_Rdy 	: in 	std_logic_vector;
149							signal 	Inp_Data 	: out 	Input2Daq_Data_a;
150							signal	Clk			: in	std_logic;
151									Offset		: in	integer	:= 0) is
152			variable DataCnt_v	: unsigned(7 downto 0) := to_unsigned(Offset, 8);
153		begin
154			assert EndType = NoEnd_s or EndType = Trigger_s or EndType = Timeout_s 
155				report "###ERROR###: APPLY_DATA: EndType not yet implemented" severity error;
156			-- Empty frame handling
157			if Bytes = 0 then
158				Inp_Data(Stream).Data <= X"AAAA_BBBB_CCCC_DDDD";
159				Inp_Data(Stream).Bytes <= "0000";
160				if EndType = Timeout_s then
161					Inp_Data(Stream).Last <= '1';
162					Inp_Data(Stream).IsTo <= '1';			
163				else
164					report "###ERROR###: APPLY_DATA: empty frames only supported for timeout" severity error;
165				end if;
166				wait until rising_edge(Clk) and Inp_Rdy(Stream) = '1';
167				Inp_Vld(Stream) 		<= '0';
168			-- Normal operation
169			else
170				Inp_Vld(Stream) 		<= '1';
171				for dw in 0 to (Bytes+7)/8-1 loop
172					for byte in 0 to 7 loop
173						if dw*8+byte >= Bytes then
174							Inp_Data(Stream).Data(8*(byte+1)-1 downto 8*byte)	<= (others => '0');
175						else
176							Inp_Data(Stream).Data(8*(byte+1)-1 downto 8*byte)	<= std_logic_vector(DataCnt_v);
177							DataCnt_v := DataCnt_v + 1;
178						end if;
179					end loop;
180					Inp_Data(Stream).Last <= '0';
181					Inp_Data(Stream).IsTo <= '0';
182					Inp_Data(Stream).IsTrig <= '0';			
183					if dw = (Bytes+7)/8-1 then
184						if EndType = Trigger_s then
185							Inp_Data(Stream).Last <= '1';
186							Inp_Data(Stream).IsTrig <= '1';
187						elsif EndType = Timeout_s then
188							Inp_Data(Stream).Last <= '1';
189							Inp_Data(Stream).IsTo <= '1';					
190						end if;
191					end if;
192	
193					if Bytes-dw*8 > 8 then
194						Inp_Data(Stream).Bytes <= std_logic_vector(to_unsigned(8, 4));
195					else
196						Inp_Data(Stream).Bytes <= std_logic_vector(to_unsigned(Bytes-dw*8, 4));
197					end if;
198					wait until rising_edge(Clk) and Inp_Rdy(Stream) = '1';
199				end loop;
200				Inp_Vld(Stream) 		<= '0';	
201			end if;
202		end procedure;
203		
204		procedure CheckMemData(			Bytes		: in	integer;
205										RdyDelay	: in	integer	:= 0;
206								signal 	Mem_DatData : in 	std_logic_vector;
207								signal 	Mem_DatVld 	: in 	std_logic;
208								signal 	Mem_DatRdy 	: out 	std_logic;
209								signal 	Clk			: in	std_logic;
210										Offset		: in	integer	:= 0;
211										Msg			: in	string := "") is
212			variable DataCnt_v	: integer := Offset;
213		begin
214			for dw in 0 to (Bytes+7)/8-1 loop
215				if RdyDelay > 0 then
216					Mem_DatRdy <= '0';
217					for i in 0 to RdyDelay loop
218						wait until rising_edge(Clk);
219					end loop;				
220				end if;
221				Mem_DatRdy <= '1';
222				wait until rising_edge(Clk) and Mem_DatVld = '1';
223				Mem_DatRdy <= '0';
224				for byte in 0 to 7 loop
225					if dw*8+byte >= Bytes then
226						-- nothing to compare
227					else
228						StdlvCompareInt (DataCnt_v, Mem_DatData(8*(byte+1)-1 downto 8*byte), "MEM_DATA: Wrong Data QW[" & to_string(dw) & "] Byte [" & to_string(byte) & "] - " & Msg, false); 
229						DataCnt_v := (DataCnt_v + 1) mod 256;
230					end if;
231				end loop;		
232			end loop;
233		end procedure;
234		
235		procedure CheckMemCmd(			Address		: in	integer;
236										Bytes		: in	integer;
237										RdyDelay	: in	integer	:= 0;
238								signal	Mem_CmdAddr : in 	std_logic_vector;
239								signal	Mem_CmdSize : in 	std_logic_vector;
240								signal	Mem_CmdVld 	: in 	std_logic;
241								signal	Mem_CmdRdy 	: out 	std_logic;
242								signal 	Clk			: in	std_logic;
243										Msg			: in	string := "") is
244		begin
245			if RdyDelay > 0 then
246				Mem_CmdRdy <= '0';
247			else
248				Mem_CmdRdy <= '1';
249			end if;
250			wait until rising_edge(Clk) and Mem_CmdVld = '1';
251			if RdyDelay > 0 then
252				for i in 0 to RdyDelay loop
253					wait until rising_edge(Clk);
254				end loop;				
255			end if;
256			Mem_CmdRdy <= '1';	
257			StdlCompare(1, Mem_CmdVld, "MEM CMD: Mem_CmdVld did not stay high - " & Msg);
258			StdlvCompareInt(Address, Mem_CmdAddr, "MEM_CMD: Wrong Address - " & Msg, false);
259			StdlvCompareInt(Bytes, Mem_CmdSize, "MEM_CMD: Wrong Size - " & Msg, false);
260			wait until rising_edge(Clk);
261			wait for 1 ns;
262			Mem_CmdRdy <= '0';	
263			StdlCompare(0, Mem_CmdVld, "MEM_CMD: Mem_CmdVld did not go low - " & Msg);
264		end procedure;
265		
266		procedure InitCase(	signal 	Clk		: in	std_logic;
267							signal	Rst		: out	std_logic) is
268		begin
269			ProcDone_V := (others => '0');
270			TestCase_v := -1;
271			wait until rising_edge(Clk);
272			Rst <= '1';
273			wait until rising_edge(Clk);
274			Rst <= '0';
275			wait until rising_edge(Clk);
276		end procedure;
277		
278		procedure InitSubCase(CaseNr	: in		integer) is
279		begin
280			ProcDone_V := (others => '0');
281			TestCase_v := CaseNr;
282		end procedure;
283		
284		procedure WaitForCase(			CaseNr	: in		integer;
285								signal 	Clk		: in		std_logic) is
286		begin
287			while CaseNr /= TestCase_v loop
288				wait until rising_edge(Clk);
289			end loop;
290		end procedure;
291		
292		procedure WaitAllProc(	signal	Clk		: in		std_logic) is
293		begin
294			while signed(ProcDone_V) /= -1 loop
295				wait until rising_edge(Clk);
296			end loop;
297		end procedure;
298		
299	
300	end;
